extra.modelCss:
/* Exemplos de position */

.card {
  position: relative; /* referência para absolute */
  padding: 16px;
  border: 1px solid #ddd;
  border-radius: 14px;
}

.badge {
  position: absolute;
  top: 12px;
  right: 12px;
  padding: 6px 10px;
  border-radius: 999px;
  background: #111;
  color: #fff;
  font-size: 0.875rem;
}

.topbar {
  position: sticky;
  top: 0;
  z-index: 10;
}

.floating {
  position: fixed;
  right: 16px;
  bottom: 16px;
}
